DELETE FROM system_settings
WHERE key LIKE 'ltx.%'
  AND key NOT IN ('ltx.enabled', 'ltx.lora_enabled');

INSERT OR IGNORE INTO system_settings (id, key, value, type, category, created_at, updated_at) VALUES
  (lower(hex(randomblob(12))), 'ltx.lora_enabled', 'false', 'boolean', 'ltx', datetime('now'), datetime('now'));

